import SwiftUIstruct StatCard: View {    let title: String    let icon: String    let color: Color    let average: Double    let total: Int    let period: StatisticsView.TimePeriod        var body: some View {        VStack(alignment: .leading, spacing: 12) {            HStack {                Image(systemName: icon)                    .foregroundStyle(color)                    .font(.title2)                Text(title)                    .font(.headline)                Spacer()            }                        VStack(alignment: .leading, spacing: 8) {                HStack {                    Text("Average per \(period == .week ? "day" : period == .month ? "day" : "week")")                        .font(.subheadline)                        .foregroundStyle(.secondary)                    Spacer()                    Text(String(format: "%.1f", period == .year ? (average * 7) : average))                        .font(.title2)                        .fontWeight(.semibold)                }                                HStack {                    Text("Total this \(period.rawValue.lowercased())")                        .font(.subheadline)                        .foregroundStyle(.secondary)                    Spacer()                    Text("\(total)")                        .font(.title2)                        .fontWeight(.semibold)                }            }        }        .padding()        .background(Color(uiColor: .secondarySystemGroupedBackground))        .clipShape(RoundedRectangle(cornerRadius: 12))    }}